// Clean up initial summary for downstream use
// This content feeds directly into prompt_perso_prof AND gets inserted to SB later
const summaryRaw = $('Initial_summary1').first().json.text || '';
const reportId = $('Process Survey Data1').first().json.report_id;

// Clean markdown formatting, convert to HTML (same logic as original)
let content = summaryRaw
  .replace(/###\s*\*\*([^*]+)\*\*/g, '<h5>$1</h5>')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\*([^*]+)\*/g, '$1')
  .trim();

return [{
  json: {
    report_id: reportId,
    content: content
  }
}];

// 1. MASTER SCHEMA - Maps ID to UUID and Full Question Data (ENCORE survey 00000000-0000-0000-0000-000000000003)
  const SURVEY_SCHEMA = {
    // --- SECTION 1: Getting to know you ---
    "1a": { uuid: "b2b2b2b2-0001-4000-a000-000000000001", question: "Your name", type: "short_text", options: [], description: "First and last name" },
    "1b": { uuid: "b2b2b2b2-0001-4000-a000-000000000002", question: "Your age", type: "number", options: [], description: "" },
    "1c": { uuid: "b2b2b2b2-0001-4000-a000-000000000003", question: "What region are you based?", type: "dropdown", options: ["Northern and Western Europe", "Southern and Eastern Europe", "United Kingdom (London)", "United Kingdom (Other)", "United States (High-Cost Regions)", "United States (Average-Cost Regions)", "United States (Lower-Cost Regions)", "Canada", "Australia and New Zealand", "Switzerland"], description: "If you are moving somewhere for this next stage, pick that region." },
    "1d": { uuid: "b2b2b2b2-0001-4000-a000-000000000004", question: "Where are you in the transition?", type: "multiple_choice", options: ["Still working, retirement is on the horizon", "Working, but winding down (fewer days or a lighter role)", "Recently stopped (less than a year ago)", "Stopped a while ago (more than a year)", "Semi-retired, already doing bits and pieces"], description: "" },
    "1e": { uuid: "b2b2b2b2-0001-4000-a000-000000000005", question: "When does (or did) the big change happen?", type: "dropdown", options: ["More than 2 years away", "Within 1 to 2 years", "Within a year", "It just happened", "More than a year ago"], description: "" },
    "1f": { uuid: "b2b2b2b2-0001-4000-a000-000000000006", question: "What is the highest level of education you have completed?", type: "multiple_choice", options: ["No formal education", "High school diploma or equivalent", "Associate's degree (e.g., technical college or vocational training)", "Bachelor's degree", "Master's degree", "Doctorate or professional degree (e.g., PhD, MD, JD)"], description: "" },
    "1g": { uuid: "b2b2b2b2-0001-4000-a000-000000000007", question: "What did you study?", type: "short_text", options: [], description: "Field or specialization, if applicable. Optional." },
    "1h": { uuid: "b2b2b2b2-0001-4000-a000-000000000008", question: "Who or what shapes your week right now?", type: "long_text", options: [], description: "Optional. Partner, grandchildren, care duties, travel plans, the garden. Whatever structures your time today." },

    // --- SECTION 2: The career you had ---
    "2a": { uuid: "b2b2b2b2-0002-4000-a000-000000000001", question: "What were the defining roles of your career?", type: "career_history", options: [], description: "Your most recent or most defining roles. No need for the full CV, the highlights are enough." },
    "2b": { uuid: "b2b2b2b2-0002-4000-a000-000000000002", question: "How happy were you in each of these roles?", type: "career_happiness", options: [], description: "Rate your happiness (1-10) and explain what about the role's responsibilities and the work itself affected your satisfaction - not the company culture, specific people, or circumstances." },
    "2c": { uuid: "b2b2b2b2-0002-4000-a000-000000000003", question: "How many years did you work in total?", type: "number", options: [], description: "A rough number is fine." },
    "2d": { uuid: "b2b2b2b2-0002-4000-a000-000000000004", question: "Skills, Achievements & Languages", type: "skills_achievements", options: [], description: "What you were good at and what you are proud of. This is the raw material for what comes next." },
    "2e": { uuid: "b2b2b2b2-0002-4000-a000-000000000005", question: "What were you known for?", type: "long_text", options: [], description: "The reputation you had. The thing colleagues would say about you when you were not in the room." },
    "2f": { uuid: "b2b2b2b2-0002-4000-a000-000000000006", question: "What will you absolutely NOT miss?", type: "long_text", options: [], description: "Be specific. Meetings, politics, targets, commuting, being on call..." },
    "2g": { uuid: "b2b2b2b2-0002-4000-a000-000000000007", question: "And what did you secretly love, even if you rarely said so?", type: "long_text", options: [], description: "The part of the work you would have done for free. There is usually one." },

    // --- SECTION 3: How you operate now ---
    "3a": { uuid: "b2b2b2b2-0003-4000-a000-000000000001", question: "When is your energy at its best these days?", type: "multiple_choice", options: ["Mornings, sharp and early", "Middle of the day", "It varies day to day", "Most of the day, energy is not my problem"], description: "" },
    "3b": { uuid: "b2b2b2b2-0003-4000-a000-000000000002", question: "How do social interactions affect your energy now?", type: "multiple_choice", options: ["Energized (I thrive on people)", "Somewhat energized (I enjoy it, with a limit)", "Somewhat drained (fine, but I need quiet afterwards)", "Drained (I guard my alone time)"], description: "" },
    "3c": { uuid: "b2b2b2b2-0003-4000-a000-000000000003", question: "Structure or freedom, at this stage?", type: "multiple_choice", options: ["Real structure: fixed days and standing commitments", "Some structure: a rhythm without a cage", "Mostly freedom: I commit per project or season", "Total freedom: I have earned it"], description: "" },
    "3d": { uuid: "b2b2b2b2-0003-4000-a000-000000000004", question: "How is your appetite for learning new things?", type: "multiple_choice", options: ["Strong, I actively want to master something new", "Selective, for the right subject", "Modest, I would rather apply what I already know", "Honestly low, and that is fine"], description: "" },
    "3e": { uuid: "b2b2b2b2-0003-4000-a000-000000000005", question: "Working with people decades younger than you: how does that sit?", type: "multiple_choice", options: ["Genuinely energizing, I like their pace", "Fine, as long as there is mutual respect", "A bit awkward, but workable", "I would rather work with peers"], description: "" },
    "3f": { uuid: "b2b2b2b2-0003-4000-a000-000000000006", question: "How do you handle feedback at this point in life?", type: "multiple_choice", options: ["Still hungry for it", "Open to it, if it is delivered like an adult", "I take it, but my ego has opinions", "Frankly, I am done being graded"], description: "" },
    "3g": { uuid: "b2b2b2b2-0003-4000-a000-000000000007", question: "Which of these do you recognize in yourself?", type: "multiple_choice", options: ["I can be set in my ways", "I underestimate what I know", "I overcommit and then resent it", "I need to be needed", "Impatience with slow processes", "I dismiss new tools too quickly", "I find it hard to say no", "None of these"], description: "Select all that apply. Honesty beats polish here." },

    // --- SECTION 4: What matters now ---
    "4a": { uuid: "b2b2b2b2-0004-4000-a000-000000000001", question: "Rank what matters most in this next stage", type: "ranking", options: ["**Purpose & contribution** (work that means something to someone)", "**Staying sharp** (keeping the mind engaged and challenged)", "**Social connection** (people, belonging, being part of something)", "**Structure & routine** (a reason to get up and a rhythm to the week)", "**Recognition & being valued** (expertise that still counts)", "**Income top-up** (meaningful money on top of the pension)", "**Freedom for travel & family** (protecting the flexible life)", "**Enjoyment of the work itself** (doing things I actually like doing)"], description: "(Most important on top, least important on the bottom)" },
    "4b": { uuid: "b2b2b2b2-0004-4000-a000-000000000002", question: "What does a genuinely good year look like at this stage?", type: "long_text", options: [], description: "Not a bucket list. An ordinary good year. What is in it?" },
    "4c": { uuid: "b2b2b2b2-0004-4000-a000-000000000003", question: "What do you fear most about this stage?", type: "multiple_choice", options: ["Becoming irrelevant", "Boredom and empty days", "Losing the identity my work gave me", "Losing social contact", "Going soft without a reason to stay sharp", "My partner and I driving each other mad", "Honestly nothing, I am ready"], description: "Pick up to 2. This is between you and the report." },
    "4d": { uuid: "b2b2b2b2-0004-4000-a000-000000000004", question: "The pace of technology and AI: how does it feel from where you sit?", type: "multiple_choice", options: ["Exciting, I want to stay in the game", "Manageable, I keep up where it matters", "Uncomfortable, the world moves faster than I like", "Irrelevant to what I want next"], description: "" },
    "4e": { uuid: "b2b2b2b2-0004-4000-a000-000000000005", question: "List personal interests or hobbies that matter to you", type: "interests_hobbies", options: [], description: "Provide **up to 3** (e.g. sailing, gardening, history, bridge, photography, wine, grandkids' football club...)" },

    // --- SECTION 5: Where you thrive ---
    "5a": { uuid: "b2b2b2b2-0005-4000-a000-000000000001", question: "How many hours a week do you actually want to commit?", type: "multiple_choice", options: ["Under 8 hours", "8 to 16 hours", "16 to 24 hours", "24 to 32 hours", "Depends entirely on the season or project"], description: "" },
    "5b": { uuid: "b2b2b2b2-0005-4000-a000-000000000002", question: "In person, remote, or both?", type: "multiple_choice", options: ["Mostly in person, the social part is the point", "Mostly remote, I value the freedom", "A real mix", "Depends on the work"], description: "" },
    "5c": { uuid: "b2b2b2b2-0005-4000-a000-000000000003", question: "Leading, contributing, or advising?", type: "multiple_choice", options: ["Leading, I still like being in charge", "Contributing, meaningful work without the politics", "Advising, my judgment is the product", "Mentoring, developing people one on one", "A blend, depending on the setting"], description: "" },
    "5d": { uuid: "b2b2b2b2-0005-4000-a000-000000000004", question: "Which environments are you simply done with?", type: "multiple_choice", options: ["Corporate politics and steering committees", "Targets and performance reviews", "Open-plan offices", "Rigid schedules", "Being managed by process instead of sense", "Travel-heavy work", "High-stakes pressure cookers"], description: "Optional. Pick up to 3." },
    "5e": { uuid: "b2b2b2b2-0005-4000-a000-000000000005", question: "How social should the work itself be?", type: "multiple_choice", options: ["Highly social, lots of people contact", "Regular contact with a familiar group", "Occasional contact, mostly independent work", "As little as possible"], description: "" },

    // --- SECTION 6: Practical reality ---
    "6a": { uuid: "b2b2b2b2-0006-4000-a000-000000000001", question: "Where does income from this next stage sit for you?", type: "multiple_choice", options: ["Not a factor, I am financially set", "Nice to have, it should pay something reasonable", "Needed, it has to meaningfully supplement my pension"], description: "Nobody sees this but the model. Honesty here changes the advice." },
    "6b": { uuid: "b2b2b2b2-0006-4000-a000-000000000002", question: "How mobile are you?", type: "multiple_choice", options: ["Fully mobile, happy to travel for the right thing", "Regional, within an hour or so", "Local, close to home", "Mostly home-based"], description: "" },
    "6c": { uuid: "b2b2b2b2-0006-4000-a000-000000000003", question: "Which commitments shape your calendar?", type: "multiple_choice", options: ["Grandchildren", "Caring for a partner or family member", "Extended travel plans", "Volunteer commitments I intend to keep", "My own health rhythm", "A partner's schedule", "None that constrain me"], description: "Select all that apply." },
    "6d": { uuid: "b2b2b2b2-0006-4000-a000-000000000004", question: "When do you want this next thing to start?", type: "dropdown", options: ["It already started, I am refining it", "As soon as possible", "Within 6 months", "Within a year", "Later, I am orienting first"], description: "" },
    "6e": { uuid: "b2b2b2b2-0006-4000-a000-000000000005", question: "What is your appetite for formal responsibility?", type: "multiple_choice", options: ["Yes, formal roles with real accountability suit me", "Some, if the obligations are clearly bounded", "Influence without formal liability, please", "None, no formal obligations again"], description: "Board and supervisory seats carry real legal liability and fixed obligations. Worth being honest about." },

    // --- SECTION 7: Looking ahead ---
    "7a": { uuid: "b2b2b2b2-0007-4000-a000-000000000001", question: "When you say you want to do something \"meaningful\", what do you actually mean?", type: "long_text", options: [], description: "Meaningful to whom? Your family, your field, strangers, yourself? There is no wrong answer, but there is a vague one." },
    "7b": { uuid: "b2b2b2b2-0007-4000-a000-000000000002", question: "What is the thing you always wanted to try but never had time for?", type: "long_text", options: [], description: "Serious or not. This question has surprised people." },
    "7c": { uuid: "b2b2b2b2-0007-4000-a000-000000000003", question: "What do you want Cairnly to tell you straight?", type: "multiple_choice", options: ["What kinds of work actually fit me now", "What my experience is genuinely worth in today's market", "An honest read on my personality, not flattery", "How to stay relevant in a world full of AI", "How to build a week that feels like a life, not a schedule", "Whether my own idea for this stage holds up"], description: "Select everything that applies." },
    "7d": { uuid: "b2b2b2b2-0007-4000-a000-000000000004", question: "Anything else we should know?", type: "long_text", options: [], description: "Optional. Anything that did not fit the boxes." }

  };

  // --- ROBUST DATA PROCESSING LOGIC ---
  const inputItem = $input.first().json;
  const rawResponses = inputItem.survey_responses?.responses || inputItem.body?.survey_responses?.responses || {};

  // Surface report_id + user_id so downstream nodes can reference them
  // via $('this_node').first().json.report_id without depending on rep_id1.
  const reportId = inputItem.report_id || inputItem.body?.report_id || null;
  const userId = inputItem.user_id || inputItem.body?.user_id || null;

  const formattedQuestions = [];
  let answeredCount = 0;

  for (const [id, config] of Object.entries(SURVEY_SCHEMA)) {
      let answer = rawResponses[config.uuid];

      const result = {
          questionId: id,
          question: config.question,
          type: config.type,
          description: config.description || "",
          chosen: [],
          notChosen: [],
          hasAnswer: false
      };

      if (answer !== undefined && answer !== "" && answer !== null) {
          result.hasAnswer = true;
          answeredCount++;

          if (config.type === "skills_achievements") {
              result.chosen = {
                  topSkills: answer.topSkills || [],
                  certifications: answer.certifications || [],
                  achievements: answer.achievements || "",
                  languages: answer.languages || []
              };
          }
          else if (["career_history", "career_happiness"].includes(config.type)) {
              result.chosen = Array.isArray(answer) ? answer : [answer];
          }
          else {
              let answerArray = Array.isArray(answer) ? answer : [answer];
              const cleanAnswers = answerArray.map(a => {
                  return typeof a === 'string' ? a.replace(/\*\*/g, '').trim() : a;
              });

              result.chosen = cleanAnswers;

              if (config.options && config.options.length > 0) {
                  result.notChosen = config.options.filter(opt => {
                      const optClean = opt.replace(/\*\*/g, '').trim();
                      return !cleanAnswers.some(userAns => String(userAns).includes(optClean));
                  });
              }
          }
      } else {
          result.chosen = [];
          result.notChosen = config.options || [];
      }

      formattedQuestions.push(result);
  }

  return [{
      report_id: reportId,
      user_id: userId,
      preferred_language: inputItem.preferred_language || inputItem.body?.preferred_language || 'en',
      summary: {
          totalQuestions: Object.keys(SURVEY_SCHEMA).length,
          answeredQuestions: answeredCount
      },
      questions: formattedQuestions
  }];

// ---------------- CONFIG ----------------
const SUBHEADER_PATTERNS_ALL = {
  en: {
  approach: [
    "Personality and Interaction Style",
    "Impact in Different Environments",
    "Key Insight"
  ],
  strengths: [
    "Identifying Your Core Strengths",
    "Leveraging Strengths in Your Career",
    "Key Insight"
  ],
  development: [
    "Understanding Potential Growth Areas",
    "Implications for Your Growth",
    "Key Insight"
  ],
  values: [
    "Identifying Your Core Values",
    "Values in Career Decisions",
    "Key Insight"
  ]
},
  nl: {
  approach: [
    "Persoonlijkheid en interactiestijl",
    "Impact in verschillende omgevingen",
    "Belangrijkste inzicht"
  ],
  strengths: [
    "Je kernkwaliteiten in kaart",
    "Je sterke punten benutten in je loopbaan",
    "Belangrijkste inzicht"
  ],
  development: [
    "Inzicht in je groeigebieden",
    "Wat dit betekent voor je groei",
    "Belangrijkste inzicht"
  ],
  values: [
    "Je kernwaarden in kaart",
    "Waarden in loopbaankeuzes",
    "Belangrijkste inzicht"
  ]
}
};
const __lang = ($('Process Survey Data1').first().json.preferred_language === 'nl') ? 'nl' : 'en';
const SUBHEADER_PATTERNS = SUBHEADER_PATTERNS_ALL[__lang];

// ---------------- HELPERS ----------------
function cleanMarkdown(text) {
  return text
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/__(.*?)__/g, '$1')
    .replace(/\*(.*?)\*/g, '$1')
    .trim();
}

function extractSections(content, sectionType) {
  const patterns = SUBHEADER_PATTERNS[sectionType] || [];
  if (patterns.length === 0) return [];

  const regex = new RegExp(`(${patterns.join('|')}):?`, 'gi');
  const parts = content.split(regex).filter(Boolean);
  const sections = [];

  for (let i = 0; i < parts.length; i++) {
    const p = parts[i].trim();
    if (patterns.some(ph => new RegExp(ph, 'i').test(p))) {
      const subheader = p.replace(/:$/, '').trim();
      const next = parts[i + 1] ? parts[i + 1].trim() : '';
      sections.push({ subheader, content: next });
      i++;
    }
  }
  // Fallback: if no known subheaders matched (e.g. localized text the
  // patterns don't cover), keep the whole section as one block instead of
  // dropping it. Guarantees no section is ever lost to a pattern miss.
  if (sections.length === 0) {
    const whole = content.trim();
    return whole ? [{ subheader: '', content: whole }] : [];
  }
  return sections;
}

// ---------------- SOURCE DATA ----------------
const narrativeData = $('generate_personality_narrative1').first().json;
const reportId = $('Process Survey Data1').first().json.report_id;

// Get the init_summary content from Prep node (already cleaned HTML)
const initSummaryContent = $('Prep init_summary').first().json.content;

// ============== Extract personality_scores tag ==============
// The prompt appends a hidden <personality_scores>{...}</personality_scores>
// tag at the very end of the narrative. Pull it out, parse the JSON, and
// strip the tag from the text BEFORE we parse sections so the prose stays
// clean. The scores get attached to the `approach` section row's metadata
// column, where the dashboard's Personality Radar reads them from.
let personalityScores = null;
let narrativeText = narrativeData.text || '';
const scoresMatch = narrativeText.match(/<personality_scores>\s*([\s\S]*?)\s*<\/personality_scores>/i);
if (scoresMatch) {
  try {
    personalityScores = JSON.parse(scoresMatch[1].trim());
  } catch (err) {
    console.warn('[extract_report_sections] personality_scores JSON parse failed:', err.message);
  }
  narrativeText = narrativeText.replace(scoresMatch[0], '').trim();
}
// ============================================================

// ---------------- NARRATIVE EXTRACTION ----------------
const titleRegex = /#{1,3}\s*([^\n#]+)/g;
const titles = [];
let match;
while ((match = titleRegex.exec(narrativeText)) !== null) {
  titles.push(match[1].trim());
}

const contents = narrativeText.split(/#{1,3}\s*[^\n#]+\n*/g);
contents.shift();

const sectionTypes = ['approach', 'strengths', 'development', 'values'];
const parsedSections = [];

for (let i = 0; i < contents.length; i++) {
  const sectionType = sectionTypes[i];
  const raw = cleanMarkdown(contents[i]);
  parsedSections.push(extractSections(raw, sectionType));
}

// ---------------- OUTPUT ALL 5 SECTIONS ----------------
// init_summary + 4 narrative sections, all inserted to SB in one batch.
// Approach gets the personality_scores attached as metadata.
// Other sections leave metadata null.
const allSections = [
  {
    section_type: 'init_summary',
    title: 'Initial Summary',
    content: initSummaryContent,
    isRawContent: true,
    metadata: null
  },
  {
    section_type: 'approach',
    title: titles[0] || null,
    content: parsedSections[0] || [],
    metadata: personalityScores ? { personality_scores: personalityScores } : null
  },
  { section_type: 'strengths',   title: titles[1] || null, content: parsedSections[1] || [], metadata: null },
  { section_type: 'development', title: titles[2] || null, content: parsedSections[2] || [], metadata: null },
  { section_type: 'values',      title: titles[3] || null, content: parsedSections[3] || [], metadata: null }
];

return allSections
  .filter(s => s.content && (s.isRawContent || (Array.isArray(s.content) && s.content.length > 0)))
  .map(s => {
    let formatted;

    if (s.isRawContent) {
      formatted = s.content;
    } else {
      formatted = s.content.map(block => {
        const subheader = block.subheader && block.subheader.trim()
          ? `<h5>${block.subheader}</h5>\n\n`
          : '';
        const text = block.content || '';
        return `${subheader}${text}`;
      }).join('\n\n');
    }

    // CRITICAL: every row MUST have the same set of keys. PostgREST
    // bulk insert (PGRST102) rejects arrays where keys differ across rows.
    // metadata is always present and is null unless this is the approach row.
    return {
      report_id: reportId,
      section_type: s.section_type,
      title: s.title,
      content: formatted,
      metadata: s.metadata ?? null,
      language: __lang
    };
  });
